module top_module( max, q, clk, rst ) ;parameter   size_cnt = 8 ;
    input   [size_cnt-1:0]          max ;
    output                          q ;
    input                           clk ;
    input                           rst ;
    reg                             q ;

    reg     [size_cnt-1:0]          cntr ;


    always  @( posedge clk or posedge rst )
        if ( rst )
            cntr <= 0 ;
        else
            if ( cntr == 0 )
                cntr <= max ;                        
            else
                cntr <= cntr - 1 ;


    always  @( posedge clk )
        if ( cntr == 1 )
            q <= 'b1 ;
        else
            q <= 'b0 ;endmodule
